# RAM Budget

all `*.js` scripts are carried as inline constants and written to host instead of `scp`ing

const CORE_CAP = 2;

const excess = Math.max(0, availableRam - CORE_CAP);

// Dynamic split of the excess
const authWeight = calculateAuthPriority();   // higher when we need to breach
const farmWeight = calculateFarmPriority();   // higher when we want to press/harvest

const totalWeight = authWeight + farmWeight;

const authBudget = excess * (authWeight / totalWeight);
const farmBudget = excess * (farmWeight / totalWeight);

